local LMapBase = LMapBase
---@class LFightIdleMap:LMapBase
local LFightIdleMap = LxClass("LFightIdleMap",LMapBase)

-----------------------------------------------------------------
local typeMapBTIdleController = typeof(CardEHT.MapBTIdleController)
local typeMapBTIdleLayer = typeof(CardEHT.MapBTIdleLayer)

local BtIdlePathUtil = CardEHT.BtIdlePathUtil

-----------------------------------------------------------------
function LFightIdleMap:LFightIdleMap()
	BtIdlePathUtil.AddBtIdleGridGraph()
end

function LFightIdleMap:OnDestroy()
	if gLFightIdleManager then gLFightIdleManager:Destroy() end
	
	BtIdlePathUtil.RemoveAstar()

	LMapBase.OnDestroy(self)
end

function LFightIdleMap:OnCreate()
	LMapBase.OnCreate(self)

	self._refreshMapFun = function ()
		local scene = LGameFunction.GetMainScene()
		local curMap = scene:GetCurMap()
		if curMap:GetMapClassName() ~= "LFightIdleMap" then
			return
		end

		GF.ChangeMap("LFightIdleMap")
	end


end

function LFightIdleMap:OnResetMap()
	GF.OpenWnd("UIMinFight")
	-- GF.OpenWnd("WndBtIdleMiniMap")
	self:InitCurrentBtIdleData()

	-- BtIdlePathUtil.DrawGrid(true)
end
function LFightIdleMap:OnExitMap()
	self._isEnter = nil
	gLFightIdleManager:Clear()
	self:ResetCameraPos(0)
	self:MapEventRemove(EventNames.ON_BATTLE_NODE_CHANGE,self._refreshMapFun)
end

function LFightIdleMap:CheckNeedChange()
	return true
end

-----------------------------------------------------------------

function LFightIdleMap:GetMonAttrRefId(monsterRefId)
	local ref = GameTable.MonsterFormationRef[monsterRefId]
	if not ref then return 0 end

	local retId = 0
	local gridMax = LCombatFormationConst.GRID_MAX
	for k=1,gridMax do
		local attrRefId = ref["monster"..k]
		if not string.isempty(attrRefId) then
			retId = attrRefId
			break
		end
	end
	return retId
end

function LFightIdleMap:InitCurrentBtIdleData()
	local diffLvl = gModelInstance:GetMainFightLevelOfDifficulty()
	local chapterId = gModelInstance:GetChapterId(diffLvl)
	local battleNode = gModelInstance:GetBattleNode(diffLvl)

	local missionRef = GameTable.MainInstanceMissionRef[battleNode]

	local mainSceneMonId1 = missionRef.mainSceneMonId1
	local normalMonList = LxDataHelper.ParseIntParam_Semicolon(mainSceneMonId1)

	local mainSceneMonId2 = missionRef.mainSceneMonId2
	local leaderMonList = LxDataHelper.ParseIntParam_Semicolon(mainSceneMonId2)

	local mainSceneMonId3 = missionRef.mainSceneMonId3
	local bossMonList = LxDataHelper.ParseIntParam_Semicolon(mainSceneMonId3)

	local mainSceneId = missionRef.mainSceneId

	self._sceneId = mainSceneId

	self._monList = {
		[LFightIdleConst.MON_QUALITY_NONE] = normalMonList,
		[LFightIdleConst.MON_QUALITY_LEADER] = leaderMonList,
		[LFightIdleConst.MON_QUALITY_BOSS] = bossMonList,
	}

	self._monAttrRefId = self:GetMonAttrRefId(missionRef.monster)

	self._chapterId = chapterId
	self._battleNode = battleNode

	local mapName = self._sceneId
	self:SetMapName(mapName)

	--据点列表,当前据点，和上一个据点
	self._missionList = {missionRef}
	local lastBattleNode = gModelInstance:GetLastBattleNode()
	if lastBattleNode then
		local lastMissionRef = GameTable.MainInstanceMissionRef[lastBattleNode]
		local lastMainSceneId = lastMissionRef.mainSceneId
		if lastMainSceneId == mainSceneId then
			table.insert(self._missionList, lastMissionRef)
		end
	end
end

function LFightIdleMap:OnEnterMap()
	if self._isEnter then
		self:OnExitMap()
	end
	self._isEnter = true
	self:MapEventRecv(EventNames.ON_BATTLE_NODE_CHANGE,self._refreshMapFun)
	gModelPlayer:ReqFigureData(ModelPlayer.PLAY_IMAGE_HANG)
	gLFightIdleManager:StartBtIdle(self:GetMapTrans(),self._chapterId,self._battleNode,self._sceneId,self._monList, self._monAttrRefId, self._missionList)
end

-----------------------------------------------------------------
function LFightIdleMap:InitCameraComponent()
	local layerRoot = CS.FindTrans(self._mapTrans,"LayerRoot")
	local com = layerRoot:GetComponent(typeMapBTIdleController)
	self._mapCameraCom = com
end

function LFightIdleMap:UpdateMapVisible()
	if not self:IsMapValid() then return end

	--CS.ShowObject(self._mapTrans,self._bVisible)
	local bDisableAll = not self._bVisible
	self._mapCameraCom.bDisableAll = bDisableAll
	if bDisableAll then
		self._mapCameraCom:DoDisableAll()
	end
	LMapBase.UpdateMapVisible(self)
end

function LFightIdleMap:OnCameraAdapt()
	gLFightIdleManager:OnCameraAdapt()
end

-----------------------------------------------------------------

return LFightIdleMap
